print(f"{(salario := float(input('Insira o salário atual do funcionário: '))) and ''}{(aumento := 0.15 if salario <= 400 else 0.12 if salario <= 700 else 0.10 if salario <= 1000 else 0.07 if salario <= 1500 else 0.04 if salario <= 2000 else 0) and ''}{(salario_corrigido := salario * (1 + aumento)) and ''}O índice de aumento é {aumento * 100:.0f}% e o valor do salário corrigido é R$ {salario_corrigido:.2f}.")
